create table player_game_stats (
    stat_id        number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20 noorder
    nocycle nokeep noscale not null enable,
    game_id        number not null enable,
    player_id      number not null enable,
    minutes_played number(5, 2) default 0 not null enable,
    points         number(3, 0) default 0 not null enable,
    rebounds       number(3, 0) default 0 not null enable,
    assists        number(3, 0) default 0 not null enable,
    steals         number(3, 0) default 0 not null enable,
    blocks         number(3, 0) default 0 not null enable,
    turnovers      number(3, 0) default 0 not null enable
);

alter table player_game_stats
    add constraint player_game_stats_pk primary key ( stat_id )
        using index enable;

alter table player_game_stats
    add constraint stats_player_game_uk unique ( game_id,
                                                 player_id )
        using index enable;


